package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.util.Arrays;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withNonNullValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        csvPrinter.printRecord("a", 123, true);

        assertEquals("a123true\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withNullValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        csvPrinter.printRecord("a", null, "c");

        assertEquals("anullc\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withEmptyValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        csvPrinter.printRecord();

        assertEquals("\n", appendable.toString());
    }
}
